/// Look up a scoring matrix by name (case-insensitive).
pub fn get_matrix(name: &str) -> Option<&'static StandardMatrix> {
    match name.to_lowercase().as_str() {
        "blosum45" => Some(&BLOSUM45),
        "blosum50" => Some(&BLOSUM50),
        "blosum62" => Some(&BLOSUM62),
        "blosum80" => Some(&BLOSUM80),
        "blosum90" => Some(&BLOSUM90),
        "pam250" => Some(&PAM250),
        "pam30" => Some(&PAM30),
        "pam70" => Some(&PAM70),
        _ => None,
    }
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_blosum62_defaults() {
        assert_eq!(BLOSUM62.default_gap_open, 11);
        assert_eq!(BLOSUM62.default_gap_extend, 1);
    }

    #[test]
    fn test_blosum62_scores() {
        // A-A diagonal should be 4
        assert_eq!(BLOSUM62.score(0, 0), 4);
        // A-R should be -1
        assert_eq!(BLOSUM62.score(0, 1), -1);
        // Symmetric
        assert_eq!(BLOSUM62.score(0, 1), BLOSUM62.score(1, 0));
    }

    #[test]
    fn test_blosum62_parameters() {
        let p = BLOSUM62.constants(11, 1);
        assert!((p.lambda - 0.267).abs() < 0.001);
        assert!((p.k - 0.041).abs() < 0.001);
    }

    #[test]
    fn test_get_matrix() {
        assert!(get_matrix("blosum62").is_some());
        assert!(get_matrix("BLOSUM62").is_some());
        assert!(get_matrix("pam250").is_some());
        assert!(get_matrix("nonexistent").is_none());
    }

    #[test]
    fn test_all_matrices_valid() {
        let names = ["blosum45", "blosum50", "blosum62", "blosum80", "blosum90", "pam250", "pam30", "pam70"];
        for name in &names {
            let m = get_matrix(name).unwrap_or_else(|| panic!("Matrix {} not found", name));
            assert!(m.parameters.len() > 1, "{} should have multiple parameter sets", name);
            assert_eq!(m.scores.len(), 676, "{} should have 676 scores", name);
        }
    }
}
